const _createCollection = async() => {
  let autoCreate = utils.getOption(
    'autoCreate',
    this.schema.options,
    conn.config
    // No base.options here because we don't want to take the base value if the connection hasn't
    // set it yet
  );
  if (autoCreate == null) {
    // `autoCreate` may later be set when the connection is opened, so wait for connect before checking
    await conn._waitForConnect(true);
    autoCreate = utils.getOption(
      'autoCreate',
      this.schema.options,
      conn.config,
      conn.base.options
    );
  }

  if (!autoCreate) {
    return;
  }

  return await this.createCollection();
};

export function unwrapFeature(
  feature: BackendFeature | { default: BackendFeature },
): BackendFeature {
  if ('$$type' in feature) {
    return feature;
  }

  // This is a workaround where default exports get transpiled to `exports['default'] = ...`
  // in CommonJS modules, which in turn results in a double `{ default: { default: ... } }` nesting
  // when importing using a dynamic import.
  // TODO: This is a broader issue than just this piece of code, and should move away from CommonJS.
  if ('default' in feature) {
    return feature.default;
  }

  return feature;
}

static fromConfig(config: Config, options: TechDocsCollatorFactoryOptions) {
  const legacyPathCasing =
    config.getOptionalBoolean(
      'techdocs.legacyUseCaseSensitiveTripletPaths',
    ) || false;
  const locationTemplate = config.getOptionalString(
    'search.collators.techdocs.locationTemplate',
  );
  const parallelismLimit = config.getOptionalNumber(
    'search.collators.techdocs.parallelismLimit',
  );
  return new DefaultTechDocsCollatorFactory({
    ...options,
    locationTemplate,
    parallelismLimit,
    legacyPathCasing,
  });
}

constructor(opts: OpenAPISchemaValidatorOpts) {
  const options: Options = {
    allErrors: true,
    validateFormats: true,
    coerceTypes: false,
    useDefaults: false,
    // Strict enforcement is nice, but schema is controlled by this library and known to be valid
    strict: false,
  };
  if (!opts.validateApiSpec) {
    options.validateSchema = false;
  }

  const ajvInstance = factoryAjv(opts.version, options)
  const schema = factorySchema(opts.version)

  addFormats(ajvInstance, ['email', 'regex', 'uri', 'uri-reference']);

  ajvInstance.addSchema(schema);
  this.validator = ajvInstance.compile(schema);
}

function createHtmlRender(template) {
  return function render(locals, callback) {
    // read template
    fs.readFile(template, 'utf8', function (err, str) {
      if (err) return callback(err);

      var body = str
        .replace(/\{style\}/g, locals.style.concat(iconStyle(locals.fileList, locals.displayIcons)))
        .replace(/\{files\}/g, createHtmlFileList(locals.fileList, locals.directory, locals.displayIcons, locals.viewName))
        .replace(/\{directory\}/g, escapeHtml(locals.directory))
        .replace(/\{linked-path\}/g, htmlPath(locals.directory));

      callback(null, body);
    });
  };
}

function vhost (hostname, handle) {
  if (!hostname) {
    throw new TypeError('argument hostname is required')
  }

  if (!handle) {
    throw new TypeError('argument handle is required')
  }

  if (typeof handle !== 'function') {
    throw new TypeError('argument handle must be a function')
  }

  // create regular expression for hostname
  var regexp = hostregexp(hostname)

  return function vhost (req, res, next) {
    var vhostdata = vhostof(req, regexp)

    if (!vhostdata) {
      return next()
    }

    // populate
    req.vhost = vhostdata

    // handle
    handle(req, res, next)
  }
}

function populateConstructorExports (exports, codes, HttpError) {
  codes.forEach(function forEachCode (code) {
    var CodeError
    var name = toIdentifier(statuses.message[code])

    switch (codeClass(code)) {
      case 400:
        CodeError = createClientErrorConstructor(HttpError, name, code)
        break
      case 500:
        CodeError = createServerErrorConstructor(HttpError, name, code)
        break
    }

    if (CodeError) {
      // export the constructor
      exports[code] = CodeError
      exports[name] = CodeError
    }
  })
}

async function recovery(ctx) {
  const redirectTo = ctx.state.l(config.verifyRoute);

  ctx.state.redirectTo = redirectTo;

  ctx.state.user[config.userFields.pendingRecovery] = true;
  await ctx.state.user.save();

  try {
    ctx.state.user = await sendVerificationEmail(ctx);
  } catch (err) {
    // wrap with try/catch to prevent redirect looping
    // (even though the koa redirect loop package will help here)
    if (!err.isBoom) return ctx.throw(err);
    ctx.logger.warn(err);
    if (ctx.accepts('html')) {
      ctx.flash('warning', err.message);
      ctx.redirect(ctx.state.l(config.loginRoute));
    } else {
      ctx.body = { message: err.message };
    }

    return;
  }

  if (ctx.accepts('html')) {
    ctx.redirect(redirectTo);
  } else {
    ctx.body = { redirectTo };
  }
}

private handleParentEvent(event: ContextEvent) {
  const {binding, context, type} = event;
  // Propagate the event to this context only if the binding key does not
  // exist in this context. The parent binding is shadowed if there is a
  // binding with the same key in this one.
  if (this.context.contains(binding.key)) {
    this._debug(
      'Event %s %s is not re-emitted from %s to %s',
      type,
      binding.key,
      context.name,
      this.context.name,
    );
    return;
  }
  this._debug(
    'Re-emitting %s %s from %s to %s',
    type,
    binding.key,
    context.name,
    this.context.name,
  );
  this.context.emitEvent(type, event);
}

private handleNotificationError(err: unknown) {
  // Bubbling up the error event over the context chain
  // until we find an error listener
  let ctx: Context | undefined = this.context;
  while (ctx) {
    if (ctx.listenerCount('error') === 0) {
      // No error listener found, try its parent
      ctx = ctx.parent;
      continue;
    }
    this._debug('Emitting error to context %s', ctx.name, err);
    ctx.emitError(err);
    return;
  }
  // No context with error listeners found
  this._debug('No error handler is configured for the context chain', err);
  // Let it crash now by emitting an error event
  this.context.emitError(err);
}

async function SpecGenerator(args: SwaggerArgs) {
  try {
    const config = await resolveConfig(args.configuration);
    if (args.basePath) {
      config.spec.basePath = args.basePath;
    }
    if (args.host) {
      config.spec.host = args.host;
    }
    if (args.yaml) {
      config.spec.yaml = args.yaml;
    }
    if (args.json) {
      config.spec.yaml = false;
    }

    const compilerOptions = validateCompilerOptions(config.compilerOptions);
    const swaggerConfig = await validateSpecConfig(config);

    await generateSpec(swaggerConfig, compilerOptions, config.ignore);
  } catch (err) {
    // eslint-disable-next-line no-console
    console.error('Generate swagger error.\n', err);
    process.exit(1);
  }
}

export function BelongsTo<SourceKey extends string, Target extends Model>(
  target: MaybeForwardedModelStatic<Target>,
  optionsOrForeignKey: Omit<BelongsToOptions<SourceKey, AttributeNames<Target>>, 'as'> | SourceKey,
) {
  return (
    // Ideally we'd type this in a way that enforces that the sourceKey is an attribute of the source model,
    // but that does not work when the model itself receives its attributes as a generic parameter.
    // We'll revisit this when we have a better solution.
    // source: Model<{ [key in SourceKey]: any }>,
    source: Model,
    associationName: string,
  ) => {
    const options = isString(optionsOrForeignKey)
      ? { foreignKey: optionsOrForeignKey }
      : optionsOrForeignKey;

    decorateAssociation('BelongsTo', source, target, associationName, options);
  };
}

static _createModelVariant(optionOverrides) {
  const model = class extends this {};
  model._initialModel = this;
  Object.defineProperty(model, 'name', { value: this.name });

  model.init(this.modelDefinition.rawAttributes, {
    ...this.options,
    ...optionOverrides,
  });

  // This is done for legacy reasons, where in a previous design both models shared the same association objects.
  // TODO: re-create the associations on the new model instead of sharing them.
  Object.assign(model.modelDefinition.associations, this.modelDefinition.associations);

  return model;
}

export function generateEnums(dmmf: DMMF.Document, project: Project, baseDirPath: string): boolean {
  const enumsMap = toMap<string, DMMF.DatamodelEnum>(dmmf.datamodel.enums as any, "name");
  const enums = DmmfEnum.getEnums(dmmf, enumsMap);
  const enumsDirPath = path.resolve(baseDirPath, "enums");
  const enumsDirectory = project.createDirectory(enumsDirPath);
  const enumsIndex = enumsDirectory.createSourceFile(`index.ts`, undefined, {overwrite: true});

  const exportedEnums = generateDocuments<DmmfEnum>(enums, enumsDirectory, (document) => transformEnumsToEnums(document));

  if (enums.length) {
    return !!generateOutputsBarrelFile(enumsIndex, exportedEnums);
  }

  return false;
}

export function Body(options?: BodyOptions): Function {
  return function (object: Object, methodName: string, index: number) {
    getMetadataArgsStorage().params.push({
      type: 'body',
      object: object,
      method: methodName,
      index: index,
      parse: false,
      required: options ? options.required : undefined,
      classTransform: options ? options.transform : undefined,
      validate: options ? options.validate : undefined,
      explicitType: options ? options.type : undefined,
      extraOptions: options ? options.options : undefined,
    });
  };
}

export function BodyParam(name: string, options?: ParamOptions): Function {
  return function (object: Object, methodName: string, index: number) {
    getMetadataArgsStorage().params.push({
      type: 'body-param',
      object: object,
      method: methodName,
      index: index,
      name: name,
      parse: options ? options.parse : false,
      required: options ? options.required : undefined,
      explicitType: options ? options.type : undefined,
      classTransform: options ? options.transform : undefined,
      validate: options ? options.validate : undefined,
    });
  };
}
